{
  "steps": [
    {
      "step_id": "cb_step_1",
      "title": "Create Cranial Segmentation",
      "simple": "Go to the Segmentation Editor module and create a new segmentation named 'Cranial_Segmentation'.",
      "detailed": "This segmentation will contain the initial skull mask. Later steps will refine it to isolate the defect area for implant design. To begin, switch to the Segmentation Editor module, click 'Create new segmentation', and name it 'Cranial_Segmentation'."
    },
    {
      "step_id": "cb_step_2",
      "title": "Select Source Volume",
      "simple": "Choose the volume (scan) you wish to segment from the Source Volume dropdown.",
      "detailed": "The segmentation will be based on this volume. Ensure it is the correct scan showing the skull and the fracture region. Choose the appropriate volume from the dropdown in the Segmentation Editor."
    },
    {
      "step_id": "cb_step_3",
      "title": "Add Cranial Segment",
      "simple": "Click the 'Add' button and name the new segment 'Cranial_Segment'.",
      "detailed": "This segment will store the skull segmentation derived from thresholding. It is the region that will later be used to define the defect. Click 'Add', then set the segment name to 'Cranial_Segment'."
    },
    {
      "step_id": "cb_step_4",
      "title": "Open Threshold Tool",
      "simple": "Click the 'Threshold' button in the Segmentation Editor.",
      "detailed": "Thresholding allows you to select Hounsfield units corresponding to bone, isolating the skull from surrounding tissue. This step prepares for setting the range. Click the 'Threshold' button."
    },
    {
      "step_id": "cb_step_5",
      "title": "Set Threshold Range",
      "simple": "Enter the lowest and highest threshold values for bone.",
      "detailed": "Adjust the threshold sliders or enter values to highlight the skull. Typical bone values are around 300-3000 HU, but adjust based on your scan. The preview will show the selected region. Set the range so that the skull is fully encompassed but soft tissue is excluded."
    },
    {
      "step_id": "cb_step_6",
      "title": "Apply Threshold",
      "simple": "Click 'Apply' to create the initial skull mask.",
      "detailed": "This will generate a segment based on the threshold range, filling the 'Cranial_Segment' with the skull region. Confirm that the skull appears correctly, then click 'Apply'."
    },
    {
      "step_id": "cb_step_7",
      "title": "Select Skull Mask Segment",
      "simple": "Choose the appropriate segmentation node from the dropdown in the Skull Mask section.",
      "detailed": "The extension needs to know which segment (the one we just created) is the skull mask for subsequent crop and defect analysis. Pick the segmentation node that contains 'Cranial_Segment'."
    },
    {
      "step_id": "cb_step_8",
      "title": "Load Skull Mask",
      "simple": "Click the 'Load Skull Mask' button.",
      "detailed": "This imports the skull mask into the extension for further operations like cropping and cutting. The mask will be used as the starting point for isolating the defect."
    },
    {
      "step_id": "cb_step_9",
      "title": "Add ROI",
      "simple": "Click 'Add ROI' to create a region of interest.",
      "detailed": "The ROI defines the volume that will be cropped to remove irrelevant anatomy, speeding up subsequent processing and focusing on the skull. An ROI node will appear; you will adjust its boundaries next."
    },
    {
      "step_id": "cb_step_10",
      "title": "Adjust ROI Boundary",
      "simple": "Drag the ROI handles to enclose the skull region.",
      "detailed": "Adjust the ROI so it includes the entire skull part you want to analyze, particularly the fractured area. Exclude non-relevant structures outside the skull. This cropping step is important to isolate the surgical zone for accurate defect detection."
    },
    {
      "step_id": "cb_step_11",
      "title": "Crop to ROI",
      "simple": "Click 'Crop to ROI' to truncate the skull mask to the selected region.",
      "detailed": "This cuts the skull segmentation to just the area inside the ROI, discarding parts of the skull not relevant for the defect. This reduces computation and focuses on the region of interest."
    },
    {
      "step_id": "cb_step_12",
      "title": "Create Closed Curve",
      "simple": "Go to the Markups module and click 'Closed Curve' to create a new closed curve.",
      "detailed": "This curve will be drawn around the skull defect to define its boundary for cutting. The closed curve node allows you to place control points in 3D around the defect."
    },
    {
      "step_id": "cb_step_13",
      "title": "Draw Curve on Skull",
      "simple": "Place control points around the skull defect to outline it.",
      "detailed": "Using the closed curve markup, click on the skull model to place points that trace the perimeter of the defect (the missing bone area). Ensure the curve fully encloses the fractured region. This contour will be used to cut out the defect."
    },
    {
      "step_id": "cb_step_14",
      "title": "Select Curve Node",
      "simple": "Choose the closed curve node from the Curve selection dropdown.",
      "detailed": "The extension needs to identify which curve represents the defect boundary. Pick the curve node you just created."
    },
    {
      "step_id": "cb_step_15",
      "title": "Cut Defect",
      "simple": "Click 'Cut Defect' to remove the defect area from the skull mask.",
      "detailed": "This uses the curve to cut out the defect region from the skull segmentation, leaving only the healthy skull. The cut area will be replaced by the implant later."
    },
    {
      "step_id": "cb_step_16",
      "title": "Generate Implant",
      "simple": "Click 'Generate Implant' to create a custom implant.",
      "detailed": "The extension will generate a 3D model of an implant that fills the defect. This implant is tailored to the patient's anatomy based on the surrounding skull curvature."
    }
  ]
}
